stereotypeDefinition.onAppliedScript:
const SqlServerDatabaseProjectStereotype = "b8201720-882a-42ad-abb6-870a97815334";
const DotNetFrameworkStereotype = "f3fcc35a-4bb2-44e7-aca2-d721e047a4c9";

let stereotype = element.getStereotype(SqlServerDatabaseProjectStereotype);

if (element.hasStereotype(DotNetFrameworkStereotype)) {
    stereotype.getProperty("Project Type").setValue(".NET Framework");
}

stereotypeDefinition.onChangedScript:
const SqlServerDatabaseProjectStereotype = "b8201720-882a-42ad-abb6-870a97815334";
const DotNetFrameworkStereotype = "f3fcc35a-4bb2-44e7-aca2-d721e047a4c9";

let stereotype = element.getStereotype(SqlServerDatabaseProjectStereotype);

if (stereotype.getProperty("Project Type").getValue() === "SDK") {
    if (element.hasStereotype(DotNetFrameworkStereotype)) {
        element.removeStereotype(DotNetFrameworkStereotype);
    }
} else if (stereotype.getProperty("Project Type").getValue() === ".NET Framework") {
    if (!element.hasStereotype(DotNetFrameworkStereotype)) {
        element.addStereotype(DotNetFrameworkStereotype);
    }
}
